   112→function upsertSessionFromEvent(entry) {
   113→	if (!entry?.key) return false;
   114→	sessionStore.upsert(entry);
   115→	var legacy = S.sessions.slice();
   116→	var idx = legacy.findIndex((session) => session.key === entry.key);
   117→	if (idx >= 0) {
   118→		legacy[idx] = { ...legacy[idx], ...entry };
   119→	} else {
   120→		legacy.push({ ...entry });
   121→	}
   122→	S.setSessions(legacy);
   123→	renderSessionList();
   124→	return true;
   125→}
   126→
   127→function removeSessionFromEvent(sessionKey) {
   128→	if (!sessionKey) return false;
   129→	var removedActive = sessionStore.activeSessionKey.value === sessionKey;
   130→	var removed = sessionStore.remove(sessionKey);
   131→	if (!removed) return false;
   132→	clearSessionHistoryCache(sessionKey);
   133→	S.setSessions(S.sessions.filter((session) => session.key !== sessionKey));
   134→	renderSessionList();
   135→	if (!removedActive) return true;
   136→	var nextKey = sessionStore.activeSessionKey.value || "main";
   137→	S.setActiveSessionKey(nextKey);
   138→	if (location.pathname.startsWith("/chats/")) {
   139→		navigate(sessionPath(nextKey));
   140→	}
   141→	return true;
   142→}
