   148→			fetchSessions();
   149→		}
   150→		return;
   151→	}
   152→	if (upsertSessionFromEvent(payload.entry || null)) return;
   153→	if (payload.kind === "created" || payload.kind === "patched") {
   154→		fetchSessions();
   155→	}
   156→});
