     1→// ── i18n core module ────────────────────────────────────────
     2→//
     3→// Single entry point for all translations. Uses i18next under the hood.
     4→// English is loaded eagerly; other locales are lazy-loaded on demand.
     5→//
     6→// Exports:
     7→//   locale       – reactive Preact signal for current locale
     8→//   t(key, opts) – global translation function for imperative DOM code
     9→//   useTranslation(ns) – Preact hook that subscribes to locale signal
    10→//   setLocale(lng)     – switch language, persist to localStorage
    11→//   init()             – initialise i18next, load English bundles
    12→//   translateStaticElements(root) – translate static data-i18n elements/attrs
    13→
    14→import { signal, useComputed } from "@preact/signals";
    15→import i18next from "i18next";
    16→
    17→var STORAGE_KEY = "moltis-locale";
    18→var initPromise = null;
    19→var SUPPORTED_LOCALES = new Set(["en", "fr", "zh"]);
    20→export var supportedLocales = Object.freeze(["en", "fr", "zh"]);
    21→
    22→function normalizeLocaleTag(value) {
    23→	if (!value) return "en";
    24→	var tag = String(value).trim().replace("_", "-");
    25→	if (!tag) return "en";
    26→	var idx = tag.indexOf("-");
    27→	if (idx !== -1) {
    28→		tag = tag.slice(0, idx);
    29→	}
    30→	return tag.toLowerCase();
    31→}
    32→
    33→function resolveSupportedLocale(value) {
    34→	var normalized = normalizeLocaleTag(value);
    35→	if (SUPPORTED_LOCALES.has(normalized)) return normalized;
    36→	return "en";
    37→}
    38→
    39→export function getPreferredLocale() {
    40→	var stored = localStorage.getItem(STORAGE_KEY);
    41→	if (stored) {
    42→		return resolveSupportedLocale(stored);
    43→	}
    44→	return resolveSupportedLocale(navigator.language || "en");
    45→}
    46→
    47→// ── Locale signal ───────────────────────────────────────────
    48→// Reactive — Preact components that read locale.value will re-render
    49→// when the language changes.
    50→export var locale = signal(getPreferredLocale());
    51→
    52→// ── Namespace registry ──────────────────────────────────────
    53→// Maps namespace name → lazy loader. English bundles are loaded eagerly
    54→// at init(); other locales load on demand via setLocale().
    55→var namespaces = {
    56→	common: (lng) => import(`./locales/${lng}/common.js`),
    57→	errors: (lng) => import(`./locales/${lng}/errors.js`),
    58→	settings: (lng) => import(`./locales/${lng}/settings.js`),
    59→	providers: (lng) => import(`./locales/${lng}/providers.js`),
    60→	chat: (lng) => import(`./locales/${lng}/chat.js`),
    61→	onboarding: (lng) => import(`./locales/${lng}/onboarding.js`),
    62→	login: (lng) => import(`./locales/${lng}/login.js`),
    63→	crons: (lng) => import(`./locales/${lng}/crons.js`),
    64→	mcp: (lng) => import(`./locales/${lng}/mcp.js`),
    65→	skills: (lng) => import(`./locales/${lng}/skills.js`),
    66→	channels: (lng) => import(`./locales/${lng}/channels.js`),
    67→	hooks: (lng) => import(`./locales/${lng}/hooks.js`),
    68→	projects: (lng) => import(`./locales/${lng}/projects.js`),
    69→	images: (lng) => import(`./locales/${lng}/images.js`),
    70→	metrics: (lng) => import(`./locales/${lng}/metrics.js`),
    71→	pwa: (lng) => import(`./locales/${lng}/pwa.js`),
    72→	sessions: (lng) => import(`./locales/${lng}/sessions.js`),
    73→	logs: (lng) => import(`./locales/${lng}/logs.js`),
    74→};
    75→
    76→// ── Load all namespace bundles for a language ───────────────
    77→function loadLanguage(lng) {
    78→	var keys = Object.keys(namespaces);
    79→	var promises = keys.map((ns) =>
    80→		namespaces[ns](lng)
    81→			.then((mod) => {
    82→				i18next.addResourceBundle(lng, ns, mod.default || mod, true, true);
    83→			})
    84→			.catch((err) => {
    85→				console.warn(`[i18n] failed to load ${lng}/${ns}`, err);
    86→			}),
    87→	);
    88→	return Promise.all(promises);
    89→}
    90→
    91→function applyDocumentLocale(lng) {
    92→	if (typeof document === "undefined" || !document.documentElement) return;
    93→	document.documentElement.lang = lng || "en";
    94→}
    95→
    96→// ── Public API ──────────────────────────────────────────────
    97→
    98→/**
    99→ * Initialise i18next with English bundles.
   100→ * Call once at app startup before any t() calls.
   101→ */
   102→export function init() {
   103→	if (initPromise) return initPromise;
   104→	initPromise = i18next
   105→		.init({
   106→			lng: locale.value,
   107→			fallbackLng: "en",
   108→			defaultNS: "common",
   109→			ns: Object.keys(namespaces),
   110→			interpolation: {
   111→				escapeValue: false, // Preact / DOM handles escaping
   112→			},
   113→			resources: {},
   114→		})
   115→		.then(() => loadLanguage("en"))
   116→		.then(() => {
   117→			// If the detected locale isn't English, load it too.
   118→			if (locale.value !== "en") {
   119→				return loadLanguage(locale.value);
   120→			}
   121→		})
   122→		.then(() => {
   123→			// Ensure i18next is set to the detected locale after bundles load.
   124→			if (i18next.language !== locale.value) {
   125→				return i18next.changeLanguage(locale.value);
   126→			}
   127→		})
   128→		.then(() => {
   129→			applyDocumentLocale(locale.value);
   130→		});
   131→	return initPromise;
   132→}
   133→
   134→/**
   135→ * Global translation function for imperative DOM code.
   136→ *   t("common:actions.save")
   137→ *   t("errors:usageLimitReached.title", { planType: "free" })
   138→ *
   139→ * Namespace can be specified with colon prefix or via the `ns` option.
   140→ */
   141→export function t(key, opts) {
   142→	return i18next.t(key, opts);
   143→}
   144→
   145→export function hasTranslation(key, opts) {
   146→	return i18next.exists(key, opts);
   147→}
   148→
   149→/**
   150→ * Preact hook — returns { t, locale } that triggers re-render on locale change.
   151→ *
