/* ══ Layout: Navigation, Sessions, Model Dropdown, Page Grid ══ */

/* ── Navigation ── */

.nav-panel {
  border-right: 1px solid var(--border);
  background: var(--surface);
  flex-direction: column;
  flex-shrink: 0;
  width: 180px;
  display: flex;
}

.nav-panel.hidden { display: none; }

.nav-link {
  color: var(--muted);
  padding: 8px 16px;
  font-size: 0.85rem;
  text-decoration: none;
  transition: background 0.15s, color 0.15s;
  display: flex;
  align-items: center;
  gap: 8px;
}

.nav-link:hover {
  background: var(--bg-hover);
  color: var(--text);
}

.nav-link.active {
  color: var(--accent);
  background: var(--accent-subtle);
}

.nav-count { display: none; }
.nav-count.visible { display: inline-block; }

/* ── Burger button ── */

.burger-btn {
  background: none;
  border: none;
  cursor: pointer;
  color: var(--muted);
  padding: 4px;
  border-radius: 4px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: color 0.15s, background 0.15s;
}

.burger-btn:hover {
  color: var(--text);
  background: var(--bg-hover);
}

/* ── Header actions ── */

.header-actions {
  display: flex;
  align-items: center;
  gap: 8px;
}

.header-link-btn {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  background: var(--surface2);
  color: var(--muted);
  text-decoration: none;
  padding: 6px 10px;
  font-size: 0.75rem;
  line-height: 1;
  cursor: pointer;

