        .unwrap_or("intake")
        .parse::<MatterPhase>()
        .map_err(ServiceError::message)?;
    let practice_area = p
        .get("practiceArea")
        .and_then(|v| v.as_str())
        .unwrap_or("other")
        .parse::<PracticeArea>()
        .map_err(ServiceError::message)?;
    let now = now_ms();
    Ok(Matter {
        id,
        contact_id: p
            .get("contactId")
            .and_then(|v| v.as_str())
            .map(ToOwned::to_owned),
        title,
        description: p
            .get("description")
            .and_then(|v| v.as_str())
            .map(ToOwned::to_owned),
        status,
        phase,
        practice_area,
        created_at: p.get("createdAt").and_then(|v| v.as_u64()).unwrap_or(now),
        updated_at: now,
    })
}

fn parse_interaction(p: Value) -> Result<Interaction, ServiceError> {
    let id = require_str(&p, "id")?.to_owned();
    let contact_id = require_str(&p, "contactId")?.to_owned();
    let kind = require_str(&p, "kind")?
        .parse::<InteractionKind>()
        .map_err(ServiceError::message)?;
    let summary = require_str(&p, "summary")?.to_owned();
    let now = now_ms();
    Ok(Interaction {
        id,
        contact_id,
        matter_id: p
            .get("matterId")
            .and_then(|v| v.as_str())
            .map(ToOwned::to_owned),
        kind,
        summary,
        channel: p
            .get("channel")
            .and_then(|v| v.as_str())
            .map(ToOwned::to_owned),
        created_at: p.get("createdAt").and_then(|v| v.as_u64()).unwrap_or(now),
        updated_at: now,
    })
}

fn now_ms() -> u64 {
    use std::time::{SystemTime, UNIX_EPOCH};
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_millis() as u64
}

