				<button
					type="button"
					class="text-[var(--muted)] hover:text-[var(--text)] bg-transparent border-0 cursor-pointer p-1 rounded"
					onClick=${onClose}
				>
					<span class="icon icon-sm icon-x"></span>
				</button>
			</div>
			<div class="p-4">${children}</div>
		</div>
	</div>`;
}

