												${m.createdAt && html`<span>· ${formatDate(m.createdAt)}</span>`}
											</div>
											${m.description && html`<p class="text-xs text-[var(--muted)] mt-1 line-clamp-2">${m.description}</p>`}
										</div>
										<div class="flex gap-1.5 shrink-0">
